import React, { useState } from "react";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Alert,
  Box,
  CircularProgress,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { signupRider, uploadRiderDocs } from "../services/api";

export default function RiderRegister() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ fullName: "", email: "", mobile: "" });
  const [docs, setDocs] = useState({ aadharFront: null, aadharBack: null, license: null });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  // ✅ File validation: only images, max 5MB
  const validateFile = (file) => {
    if (!file) return false;
    const validTypes = ["image/jpeg", "image/png", "image/jpg"];
    const maxSize = 5 * 1024 * 1024; // 5MB
    if (!validTypes.includes(file.type)) {
      setError("Only JPG/PNG images are allowed.");
      return false;
    }
    if (file.size > maxSize) {
      setError("File size should be less than 5MB.");
      return false;
    }
    return true;
  };

  const handleChange = (e) => setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));

  const handleFileChange = (e) => {
    const { name, files } = e.target;
    if (validateFile(files[0])) setDocs((prev) => ({ ...prev, [name]: files[0] }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(""); 
    setSuccess(""); 
    setLoading(true);

    try {
      // 1️⃣ Signup rider
      const res = await signupRider({ ...formData, role: "rider" });
      const riderId = res.data?.data?.id || res.data?.data?._id;
      if (!riderId) throw new Error("No Rider ID returned from server.");

      // 2️⃣ Upload documents
      const formDataUpload = new FormData();
      if (docs.aadharFront) formDataUpload.append("aadharFront", docs.aadharFront);
      if (docs.aadharBack) formDataUpload.append("aadharBack", docs.aadharBack);
      if (docs.license) formDataUpload.append("license", docs.license);

      await uploadRiderDocs(riderId, formDataUpload);

      // 3️⃣ Success message & redirect
      setSuccess("Registered successfully! Waiting for admin approval.");
      setTimeout(() => navigate("/rider-login"), 2500);
    } catch (err) {
      console.error("Rider signup error:", err);
      setError(err.response?.data?.message || err.message || "Server error. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper 
        sx={{ 
          mt: 6, 
          p: 5, 
          borderRadius: 3, 
          textAlign: "center", 
          boxShadow: 5, 
          bgcolor: "background.paper" 
        }}
      >
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>
          Rider Signup
        </Typography>
        <Typography variant="body1" sx={{ mb: 3, color: "text.secondary" }}>
          Join as a rider — create your account and upload documents.
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <form onSubmit={handleSubmit}>
          <TextField
            fullWidth
            label="Full Name"
            name="fullName"
            value={formData.fullName}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            type="email"
            label="Email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            type="tel"
            label="Mobile Number"
            name="mobile"
            value={formData.mobile}
            onChange={handleChange}
            margin="normal"
            inputProps={{ maxLength: 10 }}
            required
          />

          <Typography variant="h6" sx={{ mt: 3, mb: 1 }}>
            Upload Documents
          </Typography>
          <Box sx={{ textAlign: "left", mb: 2 }}>
            <Button variant="outlined" component="label" sx={{ mb: 1 }} fullWidth>
              Aadhar Front
              <input type="file" hidden name="aadharFront" onChange={handleFileChange} required />
            </Button>
            <Button variant="outlined" component="label" sx={{ mb: 1 }} fullWidth>
              Aadhar Back
              <input type="file" hidden name="aadharBack" onChange={handleFileChange} required />
            </Button>
            <Button variant="outlined" component="label" sx={{ mb: 2 }} fullWidth>
              License
              <input type="file" hidden name="license" onChange={handleFileChange} required />
            </Button>
          </Box>

          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{ mt: 2, bgcolor: "primary.main", fontWeight: "bold" }}
            disabled={loading}
          >
            {loading ? <CircularProgress size={24} color="inherit" /> : "Sign Up"}
          </Button>
        </form>

        <Typography sx={{ mt: 3 }}>
          Already have an account?{" "}
          <Button onClick={() => navigate("/rider-login")} sx={{ fontWeight: "bold" }}>
            LOGIN
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
